```powershell
$results = [System.Collections.Generic.List[PSObject]]::new()
$computers = Get-ADComputer -Filter * -Properties OperatingSystem | Select-Object Name, OperatingSystem

foreach ($computer in $computers) {
    $entry = [PSCustomObject]@{
        ComputerName    = $computer.Name
        OS              = $computer.OperatingSystem
        Online          = $false
        LastBoot        = 'N/A'
        DefenderEnabled = 'N/A'
        Error           = ''
    }

    $online = Test-Connection -ComputerName $computer.Name -Count 1 -Quiet -ErrorAction SilentlyContinue
    $entry.Online = $online

    if ($online) {
        try {
            $os = Get-CimInstance -ClassName Win32_OperatingSystem -ComputerName $computer.Name -ErrorAction Stop
            $entry.LastBoot = $os.LastBootUpTime

            $defender = Get-CimInstance -Namespace 'ROOT\Microsoft\Windows\Defender' -ClassName MSFT_MpComputerStatus -ComputerName $computer.Name -ErrorAction Stop
            $entry.DefenderEnabled = $defender.AntivirusEnabled
        }
        catch {
            $entry.Error = $_.Exception.Message
        }
    }

    $results.Add($entry)
}

$timestamp = Get-Date -Format 'yyyyMMdd-HHmmss'
$results | Export-Csv -Path "C:\Reports\Inventory-$timestamp.csv" -NoTypeInformation
Write-Output "Report saved: $($results.Count) computers inventoried."
```
Key points: Generic List is faster than += for large datasets. CimInstance (WMI successor) is preferred over WMI. Separate try/catch isolates failures per-machine. Timestamped filename prevents overwrites. -ErrorAction Stop is required for try/catch to work on cmdlet errors.
